import stylesText from './activity-edit.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { ACTIVITY_TYPES } from '@motivation/shared';
import type { Activity } from '@motivation/shared';

export type ActivitySourceMode = 'manual' | 'strava' | 'calendar';

const template = document.createElement('template');
template.innerHTML = `
    <div class="edit-container">
        <div class="edit-header">
            <h3>Edit Workout</h3>
        </div>

        <p class="source-note" id="source-note" hidden></p>

        <div class="form-group">
            <label for="title">Title</label>
            <input type="text" id="title" class="form-input" placeholder="e.g. Morning run">
        </div>

        <div class="form-row">
            <div class="form-group">
                <label for="type">Type</label>
                <select id="type" class="form-select">
                    ${ACTIVITY_TYPES.map(t => `<option value="${t}">${t.charAt(0).toUpperCase() + t.slice(1).replace(/_/g, ' ')}</option>`).join('')}
                </select>
            </div>
            <div class="form-group">
                <label for="date">Date</label>
                <input type="date" id="date" class="form-input">
            </div>
        </div>

        <div class="form-row">
            <div class="form-group">
                <label for="duration">Duration (min)</label>
                <input type="number" id="duration" class="form-input" min="0" placeholder="optional">
            </div>
            <div class="form-group">
                <label for="calories">Calories burned</label>
                <input type="number" id="calories" class="form-input" min="0" placeholder="optional">
            </div>
        </div>

        <div class="form-group">
            <label for="description">Notes</label>
            <input type="text" id="description" class="form-input" placeholder="optional">
        </div>

        <div class="action-buttons">
            <button class="btn-delete" id="btn-delete">Delete</button>
            <button class="btn-save" id="btn-save">Save</button>
        </div>
    </div>
`;

export class ActivityEdit extends HTMLElement {
    private _activity: Activity | null = null;
    private _sourceMode: ActivitySourceMode = 'manual';
    private _onSave: ((id: string, updates: Partial<Activity>) => void) | null = null;
    private _onDelete: ((id: string) => void) | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        const shadow = this.shadowRoot!;
        shadow.getElementById('btn-save')!.addEventListener('click', () => this.handleSave());
        shadow.getElementById('btn-delete')!.addEventListener('click', () => this.handleDelete());
    }

    set onSave(handler: (id: string, updates: Partial<Activity>) => void) {
        this._onSave = handler;
    }

    set onDelete(handler: (id: string) => void) {
        this._onDelete = handler;
    }

    set sourceMode(mode: ActivitySourceMode) {
        this._sourceMode = mode;
        this.applySourceMode();
    }

    private applySourceMode(): void {
        const shadow = this.shadowRoot!;
        const save = shadow.getElementById('btn-save') as HTMLButtonElement;
        const del = shadow.getElementById('btn-delete') as HTMLButtonElement;
        const note = shadow.getElementById('source-note') as HTMLElement;

        switch (this._sourceMode) {
            case 'manual':
                save.hidden = false;
                del.hidden = false;
                note.hidden = true;
                note.textContent = '';
                break;
            case 'strava':
                // Strava rows exist in the DB but the server forbids PATCH on synced
                // activities. Delete stays available — it will however come back on the
                // next Strava sync unless the activity is also removed in Strava.
                save.hidden = true;
                del.hidden = false;
                note.hidden = false;
                note.textContent = 'Imported from Strava. Editing is disabled; deleting here only hides it until the next sync.';
                break;
            case 'calendar':
                // Calendar activities are synthesized from Google Calendar on every load
                // and have no DB row, so neither save nor delete can do anything durable.
                save.hidden = true;
                del.hidden = true;
                note.hidden = false;
                note.textContent = 'Imported from Google Calendar. Edit or remove the event in Calendar to change it here.';
                break;
        }
    }

    set activity(val: Activity) {
        this._activity = val;
        this.populateForm();
    }

    get activity(): Activity | null {
        return this._activity;
    }

    private populateForm(): void {
        const a = this._activity;
        if (!a) return;
        const shadow = this.shadowRoot!;

        (shadow.getElementById('title') as HTMLInputElement).value = a.title;
        (shadow.getElementById('type') as HTMLSelectElement).value = a.type;
        (shadow.getElementById('date') as HTMLInputElement).value = a.date;
        (shadow.getElementById('duration') as HTMLInputElement).value = a.duration_minutes ? String(a.duration_minutes) : '';
        (shadow.getElementById('calories') as HTMLInputElement).value = a.calories_burned ? String(a.calories_burned) : '';
        (shadow.getElementById('description') as HTMLInputElement).value = a.description ?? '';
    }

    private handleSave(): void {
        if (!this._activity || !this._onSave) return;
        const shadow = this.shadowRoot!;

        const title = (shadow.getElementById('title') as HTMLInputElement).value.trim();
        if (!title) return;

        const duration = parseInt((shadow.getElementById('duration') as HTMLInputElement).value, 10);
        const calories = parseInt((shadow.getElementById('calories') as HTMLInputElement).value, 10);

        const updates: Partial<Activity> = {
            title,
            type: (shadow.getElementById('type') as HTMLSelectElement).value,
            date: (shadow.getElementById('date') as HTMLInputElement).value,
            description: (shadow.getElementById('description') as HTMLInputElement).value.trim() || undefined,
            duration_minutes: isNaN(duration) ? undefined : duration,
            calories_burned: isNaN(calories) ? undefined : calories,
        };

        this._onSave(this._activity.id, updates);
    }

    private handleDelete(): void {
        if (!this._activity || !this._onDelete) return;
        const title = this._activity.title;
        const message = this._sourceMode === 'strava'
            ? `Delete "${title}"?\n\nThis activity is imported from Strava and will reappear on the next sync unless you also delete it in Strava.`
            : `Delete "${title}"?`;
        if (confirm(message)) {
            this._onDelete(this._activity.id);
        }
    }
}

customElements.define('activity-edit', ActivityEdit);
